export const getGetReferralsUrl = (params?: GetReferralsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/referrals?${stringifiedParams}`
    : `/api/referrals`;
};

export const getReferrals = async (
  params?: GetReferralsParams,
  options?: RequestInit,
): Promise<ReferralInfo> => {
  return customFetch<ReferralInfo>(getGetReferralsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetReferralsQueryKey = (params?: GetReferralsParams) => {
  return [`/api/referrals`, ...(params ? [params] : [])] as const;
};

export const getGetReferralsQueryOptions = <
  TData = Awaited<ReturnType<typeof getReferrals>>,
  TError = ErrorType<unknown>,
>(
  params?: GetReferralsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getReferrals>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetReferralsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getReferrals>>> = ({
    signal,
  }) => getReferrals(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getReferrals>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetReferralsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getReferrals>>
>;
export type GetReferralsQueryError = ErrorType<unknown>;

/**
 * @summary Get referral list and link
 */

export function useGetReferrals<
  TData = Awaited<ReturnType<typeof getReferrals>>,
  TError = ErrorType<unknown>,
>(
  params?: GetReferralsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getReferrals>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetReferralsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Get real-time TON price from Binance
 */
